import { db } from "./firebase";
import { ref, push, set, get, child, update } from "firebase/database";
import { Vendor } from "@/types";

const COLLECTION_NAME = "vendors";

export const addVendor = async (vendor: Omit<Vendor, 'id' | 'createdAt'>) => {
    try {
        const vendorsRef = ref(db, COLLECTION_NAME);
        const newVendorRef = push(vendorsRef);

        await set(newVendorRef, {
            ...vendor,
            id: newVendorRef.key,
            createdAt: new Date().toISOString(),
        });

        return newVendorRef.key;
    } catch (error) {
        console.error("Error adding vendor: ", error);
        throw error;
    }
};

export const getVendors = async (): Promise<Vendor[]> => {
    try {
        const dbRef = ref(db);
        const snapshot = await get(child(dbRef, COLLECTION_NAME));

        if (snapshot.exists()) {
            const data = snapshot.val();
            // Convert object of objects to array
            return Object.values(data).map((v: any) => ({
                ...v,
                createdAt: new Date(v.createdAt),
            })) as Vendor[];
        }
        return [];
    } catch (error) {
        console.error("Error fetching vendors", error);
        return [];
    }
};

export const updateVendorStatus = async (vendorId: string, status: 'ACTIVE' | 'INACTIVE') => {
    const vendorRef = ref(db, `${COLLECTION_NAME}/${vendorId}`);
    await update(vendorRef, { status });
};
export const getVendor = async (id: string): Promise<Vendor | null> => {
    const dbRef = ref(db);
    const snapshot = await get(child(dbRef, `${COLLECTION_NAME}/${id}`));
    if (snapshot.exists()) {
        return { ...snapshot.val(), id } as Vendor;
    }
    return null;
};
